import{_ as i,o,c as t,ae as r}from"./chunks/framework.RRduUuAx.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/marx/chapter-1.md","filePath":"szu/marx/chapter-1.md"}'),e={name:"szu/marx/chapter-1.md"};function n(s,l,a,d,g,c){return o(),t("div",null,[...l[0]||(l[0]=[r('<h2 id="第一节、物质世界和实践" tabindex="-1">第一节、物质世界和实践 <a class="header-anchor" href="#第一节、物质世界和实践" aria-label="Permalink to &quot;第一节、物质世界和实践&quot;">​</a></h2><h3 id="物质世界的客观存在" tabindex="-1">物质世界的客观存在 <a class="header-anchor" href="#物质世界的客观存在" aria-label="Permalink to &quot;物质世界的客观存在&quot;">​</a></h3><ol><li>哲学的基本问题 <ul><li><strong>思维和存在或意识与物质的关系问题</strong>是<code>哲学的基本问题</code>。</li><li>世界的本原（本体论） <ul><li>唯物主义（<strong>认为物质是本原的，第一性的，意识是派生的，第二性的。</strong>）</li><li>唯心主义（<strong>认为意识是本原的，第一性的，物质是派生的，第二性的。</strong>）</li></ul></li><li>思维和存在有无同一性（认识论） <ul><li>可知论（<strong>承认思维与存在的同一性，认为世界是可以认识的</strong>）</li><li>不可知论（<strong>否认思维与存在的同一性，认为世界是不可能认识的</strong>）</li></ul></li><li>[选择题]哲学基本问题第二方面内容主要回答的是<code>世界可否被认识的问题</code></li><li>[选择题]唯物主义与唯心主义的区别在于如何回答<code>世界的本质是什么问题</code></li></ul></li><li>社会历史观的基本问题<br><strong>社会存在与社会意识的关系问题</strong>是社会历史观的基本问题。 <ul><li>何为第一性 <ul><li>历史唯物主义（<strong>认为社会存在决定社会意识</strong>）</li><li>历史唯心主义（<strong>认为社会意识决定社会存在</strong>）</li></ul></li></ul></li><li>关于<code>世界如何存在的问题</code><ul><li>辩证法<br> 认为世界上的事物都是<strong>相互联系的，运动发展的，发展的根本原因在于事物的内部矛盾。</strong></li><li>形而上学<br> 认为世界上的事物都是<strong>彼此孤立的，静止不变的，否认事物内部矛盾的存在。</strong></li><li>[选择题]<code>唯物辩证法和形而上学是两种根本对立的发展观，是关于世界如何存在的两种根本不同的观点。</code></li><li>[选择题]辩证法和形而上学的区别是在于如何回答<code>世界的存在是怎样的问题</code></li><li>[选择题]唯物辩证法和形而上学根本对立和斗争的焦点在于，是否承认<code>矛盾是事物发展的动力</code></li></ul></li><li>世界的本质 <ul><li><code>世界的本质问题</code>，实质上是世界的<strong>统一性</strong>问题。即，纷繁复杂、多种多样的万事万物有无一个<strong>共同的本质或本原。</strong></li><li>对于这个问题的回答存在着<strong>一元论和二元论、唯物主义和唯心主义</strong>的对立。</li><li>一元论 <ul><li>唯物主义 唯物主义一元论认为世界的本原是物质，世界<strong>统一</strong>于物质。唯物主义哲学随着社会实践和科学的发展，<code>**唯物主义哲学发展经历的三种基本形态**</code>： <ul><li><strong>古代</strong>的朴素唯物主义<br> **把世界的本质或本原归结为某一种或几种具体的物质形态。**比如中国的“五行说”。</li><li><strong>近代</strong>的形而上学唯物主义<br> 以当时在自然科学中占主导地位的原子论为依据，把原子看成是世界的本原。<strong>它的错误</strong>是把原子的个性当成物质的共性。</li><li><strong>现代</strong>的辩证唯物主义和历史唯物主义<br> 马克思、恩格斯创立的辩证唯物主义和历史唯物主义是唯物主义哲学的第三个历史心态，是唯物主义哲学的<strong>最高形态。</strong><br> 辩证唯物主义和历史唯物主义是<strong>彻底的唯物主义一元论</strong>，它的基本观点：<br> 第一，承认世界的统一性，坚持一元论；第二，认为世界统一于物质，坚持唯物主义一元论；第三，认为世界是运动发展的，无限多样性的统一。</li></ul></li><li>唯心主义 <ul><li>主观唯心主义（<strong>把人的主观意识（人的感觉、经验、思想等）夸大为唯一的实在。</strong>）</li><li>客观唯心主义（<strong>把某种“客观”精神（“理念”、“绝对精神”、“天理”等）说成是世界的本原。</strong>）</li></ul></li></ul></li><li>二元论 （物质、意识，并行存在）</li><li>[选择题]<code>承认世界的统一性，认为世界上的万事万物有一个共同的本质或本原，就是一元论</code>。</li></ul></li><li>物质的定义 <ul><li>物质是不依赖于意识又能为意识所反映的<strong>客观实在</strong>。<code>物质的**唯一特性**是**客观实在性。**</code></li><li>列宁的物质定义是：“物质是标志客观实在的哲学范畴，这种客观实在是人通过感觉感知的，它不依赖于我们的感觉而存在，为我们的感觉所复写、摄影、反映。”</li><li>理论意义：第一，它指出<strong>物质不依赖于意识的客观实在</strong>，同唯心主义划清了界限；第二，它指出<strong>物质是可以被人们认识的</strong>，同不可认知论划清了界限；第三，它指出<strong>客观实在性是一切物质的共性</strong>,克服了旧唯物主义物质观的局限性。</li><li>[选择题]<code>客观实在性作为物质的唯一特性，表明它是一切物质的共性</code></li></ul></li><li>运动是物质的根本属性 <ul><li>**运动是物质的根本属性和存在方式。**运动是标志物质世界一切事物和现象的变化的过程的哲学范畴。</li><li><code>**运动是物质的固有属性，物质和运动不可分割**。</code><ul><li>一方面，世界上不存在脱离运动的物质。物质世界的运动是无条件的、永恒的、绝对的。否认物质的运动和运动的绝对性，必然<strong>导致形而上学</strong>。另一方面，世界上也不存在没有物质的运动。物质是运动的承担者，是运动的主体。否认物质是运动的承担者或者主体，必然<strong>导致唯心主义</strong>。</li><li>在承认物质绝对运动的同时，也承认事物的**相对静止状态。**所谓相对静止，是标准物质运动在一定条件下、一定范围内处于暂时稳定和平衡状态的哲学范畴。</li><li><code>相对静止有两种情形</code>： <ul><li>第一，一个事物对于另一个事物来说没有发生<strong>位置的移动。</strong></li><li>第二，事物的<strong>质没有发生根本变化</strong>,即事物质的相对稳定性。<strong>静止是有条件的、暂时的、相对的。</strong></li></ul></li></ul></li></ul></li><li>时间和空间 <ul><li>时间是物质运动的<strong>持续性、顺序性。<strong>时间的特点是</strong>一维性</strong>，即时间总是朝着一个方向向前发展。如“一寸光阴一寸金，寸金难买寸光阴”。</li><li>空间是物质运动的<strong>广延性和伸张性。</strong></li><li>时间和空间既是绝对的、无限的，又是相对的、有限的，是<strong>绝对和相对、无限和有限</strong>的统一。</li><li>绝对性、无限性指向的对象是<strong>整个物质世界。<strong>相对性、有限性指向的对象是</strong>每一具体事物。</strong></li></ul></li></ol><h3 id="实践的本质、特点、形式和作用" tabindex="-1">实践的本质、特点、形式和作用 <a class="header-anchor" href="#实践的本质、特点、形式和作用" aria-label="Permalink to &quot;实践的本质、特点、形式和作用&quot;">​</a></h3><ol><li>实践的本质<br><strong>实践的观点是马克思主义的基本观点。</strong><br> 实践是主体能动地改造和探索客体的社会性的<strong>客观物质活动。</strong><br> 人生活于其中的世界是<strong>与人的实践相联系的物质世界。</strong></li><li>实践的特点<br><code>实践具有**客观性、自觉能动性和社会历史性**三个基本特点</code>。 <ul><li>客观性：实践是客观的感性物质活动。</li><li><code>自觉能动性：实践是主体有意识、有目的的活动</code>。</li><li>社会历史性：实践是社会性的、历史性的活动。</li></ul></li><li>实践的形式<br><code>实践包括**物质生产实践、处理社会关系的实践和科学实验**三种基本形式。</code><ul><li>物质生产实践是决定其他一切实践活动产生和发展的前提。</li></ul></li></ol><h3 id="社会生活在本质上是实践的" tabindex="-1">社会生活在本质上是实践的 <a class="header-anchor" href="#社会生活在本质上是实践的" aria-label="Permalink to &quot;社会生活在本质上是实践的&quot;">​</a></h3><p>马克思主义认为，实践是人类社会产生、存在和发展的基础，是社会生活的本质。</p><ul><li><strong>劳动实践</strong>是人类和人类社会产生的决定性环节。</li><li><strong>物质生产实践</strong>是人类社会得以存在的基础。</li><li><strong>实践活动</strong>是推动社会发展的动力。</li></ul><h2 id="第二节、物质世界的普遍联系和永恒发展" tabindex="-1">第二节、物质世界的普遍联系和永恒发展 <a class="header-anchor" href="#第二节、物质世界的普遍联系和永恒发展" aria-label="Permalink to &quot;第二节、物质世界的普遍联系和永恒发展&quot;">​</a></h2><h3 id="联系与发展的普遍性与多样性" tabindex="-1">联系与发展的普遍性与多样性 <a class="header-anchor" href="#联系与发展的普遍性与多样性" aria-label="Permalink to &quot;联系与发展的普遍性与多样性&quot;">​</a></h3><ol><li><p>唯物辩证法的总特征<br> 唯物辩证法认为，物质世界是普遍联系和永恒发展的。联系的观点和发展的观点是唯物辩证法的总特征。</p></li><li><p>新事物和旧事物<br> 发展是指事物一种特殊的运动变化——上升性、前进性的运动变化，即事物由低级到高级、由简单到复杂的不断更替的运动变化过程。<strong>发展的实质是新事物的产生和旧事物的灭亡。</strong><br> 新事物是指符合事物发展规律、具有强大生命力和远大前途的事物。旧事物是指丧失了其存在的必然性、日趋灭亡的事物。<br> 区分新旧事物的<strong>根本标志</strong>在于它是否符合事物发展的必然趋势，是否具有强大的生命力和远大的发展前途。<br> 新事物必然战胜旧事物，是由新旧事物的本质特点和事物发展的辩证本性决定。<br> 事物发展的辩证本性：<br><strong>新事物战胜旧事物是一个艰难曲折的过程</strong></p></li><li><p>两种对立的发展观<br> 唯物辩证法和形而上学是两种<strong>根本对立</strong>的发展观，是关于<strong>世界如何存在</strong>的两种根本不同的观点。</p><table tabindex="0"><thead><tr><th style="text-align:center;">唯物辩证法</th><th style="text-align:center;">形而上学</th></tr></thead><tbody><tr><td style="text-align:center;">联系观点</td><td style="text-align:center;">孤立观点</td></tr><tr><td style="text-align:center;">发展变化观点</td><td style="text-align:center;">静止不变观点</td></tr><tr><td style="text-align:center;">承认事物内部矛盾</td><td style="text-align:center;">否认事物内部矛盾</td></tr></tbody></table><p>唯物辩证法认为，世界上的一切事物内部都包含着矛盾，矛盾是事物运动变化发展的根本原因。因而它主张用矛盾的观点来观察问题，坚持两点论。<strong>形而上学则根本否认事物内部矛盾的存在</strong>，认为事物的运动变化发展，都是外力推动的结果，因为只看到矛盾的一个方面，看不到另一个方面，坚持两点论。<br> 唯物辩证法与形而上学的<strong>根本对立和斗争的焦点在于是否承认矛盾是事物发展的动力。</strong></p></li><li><p>唯物辩证法<br> 唯物辩证法是关于自然、社会和思维联系和发展一般规律的科学。它是由<strong>对立统一规律、质量互变规律、否定之否定规律和一系列其他范畴</strong>构成的科学体系。</p><ul><li><code>对立统一规律揭示了事物发展的**动力和源泉**，质量互变规律揭示了事物发展的**状态和形式**，否定之否定规律揭示了事物发展的**趋势和道路**。</code>唯物辩证法的其他范畴则揭示了事物联系和发展的基本环节。</li><li>[选择题]<code>**唯物辩证法的总特征是联系与发展**</code></li></ul></li><li><p>对立统一规律的核心地位<br> 唯物辩证法的<strong>实质与核心是对立统一规律</strong>，唯物辩证法提供的<strong>最根本的认识方法是矛盾分析法</strong>。</p></li></ol><h3 id="世界联系与发展的基本规律" tabindex="-1">世界联系与发展的基本规律 <a class="header-anchor" href="#世界联系与发展的基本规律" aria-label="Permalink to &quot;世界联系与发展的基本规律&quot;">​</a></h3><p><strong>三大规律</strong></p><ol><li>对立统一规律 <ul><li>矛盾的同一性和斗争性</li><li>矛盾是事物发展的动力</li><li>矛盾的普遍性和特殊性 <ul><li>[选择题]<code>分析矛盾的特殊性就是坚持具体问题具体分析</code></li><li>分析矛盾的特殊性是正确解决矛盾的关键</li></ul></li><li>矛盾发展的不平衡性</li></ul></li><li>质量互变规律 <ul><li>质、量、度的含义</li><li>量变和质变及其辩证关系</li></ul></li><li>否之否定规律 <ul><li>辩证的否定<br> 辩证的否定观，就要对一切事物采取分析的态度，否定什么和肯定什么，批判什么和继承什么，都要从实际出发，进行具体分析，反对不加分析地肯定一切或否定一切。</li><li>事物的发展是前进性与曲折性的统一</li></ul></li></ol><h3 id="世界联系与发展的基本环节" tabindex="-1">世界联系与发展的基本环节 <a class="header-anchor" href="#世界联系与发展的基本环节" aria-label="Permalink to &quot;世界联系与发展的基本环节&quot;">​</a></h3><p><strong>五个环节</strong></p><ol><li>原因和结果 <ul><li>原理<br> 原因和结果的关系既是对立的、又是统一的。表现在：原因和结果互相依存；原因和结果在一定条件下相互转化；原因和结果是相互作用的。</li><li>意义 掌握因果的辩证关系具有重要意义。首先，只有找出事物的原因才能认识其本质和规律，提出解决问题的方法。其次，正确把握因果关系，才能总结经验教训以便指导今后的行动。</li></ul></li><li>必然性和偶然性 <ul><li>原理 必然性和偶然性之间的关系是对立统一关系；首先两者是对立的，它们是事物联系与发展中两种不同的趋势。其次，两种又是辩证统一的：必然性通过大量的偶然性表现出来；偶然性是必然性的表现形式；在一定条件下可以相互转化。</li><li>意义<br> 首先，偶然性是受必然性支配的，必然性决定着事物发展的方向和前途，所以我们必须按必然性规律办事不要被偶然现象迷惑。其次，因为必然性是通过大量偶然性表现出来的，我们应该抓住偶然性提供的机遇，揭示其背后的必然性。</li></ul></li><li>可能性和现实性</li><li>内容和形式 <ul><li><code>内容和形式是事物的内在要素和结构方式这两个不同方面</code>，二者的关系是有区别的，对立的，同时，内容与形式相互依存、密不可分。</li></ul></li><li>本质和现象</li></ol><h2 id="第三节、客观规律性与主观能动性" tabindex="-1">第三节、客观规律性与主观能动性 <a class="header-anchor" href="#第三节、客观规律性与主观能动性" aria-label="Permalink to &quot;第三节、客观规律性与主观能动性&quot;">​</a></h2><ol><li>自然规律和社会规律 <ul><li>规律和自然规律 <ul><li>规律就是物质运动发展过程中本质的、必然的、稳定的联系。两个特点：客观性；普遍性。</li><li>自然规律是在自然界各个领域起作用的规律。</li></ul></li><li>社会发展是有规律的历史过程</li><li>[选择题]<code>与自然规律相比，社会规律是通过人们的自觉活动实现的。</code></li></ul></li><li>意识及其能动作用 <ol><li>意识的起源和本质 <ul><li>意识的起源。首先意识是自然界长期发展的产物，其次，意识是社会性劳动的产物。</li><li><code>意识的本质</code>。第一，意识是人脑的机能；第二，意识是客观世界的主观映象；第三，意识是社会的产物。</li></ul></li><li>意识的能动作用 <ul><li>第一，意识活动具有目的性和计划性</li><li>第二，意识活动具有主动性、创造性</li><li>第三，意识对于人的生理活动具有一定影响作用</li><li>第四，意识能通过指导实践改造客观物质世界。这是意识的能动性最突出的表现。</li></ul></li><li>发挥主观能动性和尊重客观规律的关系</li></ol></li></ol><h2 id="第四节、解放思想-实事求是" tabindex="-1">第四节、解放思想，实事求是 <a class="header-anchor" href="#第四节、解放思想-实事求是" aria-label="Permalink to &quot;第四节、解放思想，实事求是&quot;">​</a></h2><ol><li>事实求实是马克思主义哲学的精髓<br> 事实求实是马克思主义哲学的精髓，是马克思主义中国话所形成的重大理论成果。<br> 党的思想路线内涵：一切从实际出发，理论联系实际，实事求是，在实践中检验和发展真理。这一<strong>思想路线的核心是实事求是。</strong></li><li>解放思想和实事求是的辩证统一</li></ol><h3 id="百日题库选择题题解记录" tabindex="-1">百日题库选择题题解记录 <a class="header-anchor" href="#百日题库选择题题解记录" aria-label="Permalink to &quot;百日题库选择题题解记录&quot;">​</a></h3><ul><li>处理社会关系的实践它是处理人与人之间关系的活动。主要表现为：社会管理、阶级斗争、社会革命、社会改革等</li><li><code>对立统一规律揭示了事物发展的动力和源泉，质量互变规律揭示了事物发展的状态和形式，否知否定规律揭示了事物发展的趋势和道路</code></li><li>承认世界的统一性，认为世界上的万事万物有一个共同的本质或本原，这种哲学就是一元论</li><li><code>假象同真相一样，也是客观存在的</code>。因此不能把它同主观上的错觉混为一谈。这是唯物辩证法的观点。</li><li>把意识说成是人脑的分泌物，这是一种<code>庸俗唯物主义的观点</code></li><li>唯物辩证法的规律起作用的范围和领域是<code>自然、社会和思维等所有领域</code></li><li>意识是人脑的机能，这说的是<code>人脑是意识的物质器官</code></li><li>建设中国特色社会主义既要坚持科学社会主义一般原则，又要结合中国实际。这符合<code>矛盾的普遍性和特殊性辩证关系的原理</code></li><li>规律的两个特点是<code>客观性和普遍性</code></li><li>实践作为一种感性物质活动，强调的是<code>实践具有客观物质性</code>。实践是主体能动地改造和探索客体的客观物质活动。</li><li>我们党制定和执行独立自主、自力更生以及对外开放方针的理论基础是<code>事物发展的内因和外因辩证关系的原理</code></li></ul>',23)])])}const b=i(e,[["render",n]]);export{h as __pageData,b as default};
